+
+describe('cond', () => {
+  const statechart = {
+    initial: 'a',
+    states: {
+      a: {
+        on: {
+          EVENT: {
+            b: {
+              cond: extState => extState.shouldPass,
+            },
+          },
+        },
+      },
+      b: {},
+    },
+  }
+
+  const Cond = () => (
+    <React.Fragment>
+      <State value="a">A</State>
+      <State value="b">B</State>
+    </React.Fragment>
+  )
+
+  test('pass', () => {
+    const extendedState = {
+      shouldPass: true,
+    }
+    const fixtures = {
+      a: {
+        EVENT: extendedState,
+      },
+    }
+
+    testStatechart({ statechart, fixtures, extendedState }, Cond)
+  })
+
+  test('fail', () => {
+    testStatechart({ statechart }, Cond)
+  })
+})
